INSERT INTO `events` (`id`, `title`, `description`, `date`, `location`, `image_url`, `materials_url`, `tasks_url`, `certificate_url`, `certificate_template`, `is_registration_open`, `created_at`, `updated_at`, `is_premium`) VALUES
('1768360a-a661-4028-a5d1-3483135fd374', 'Koding Interaktif dengan PictoBlox (Mulai dari 0)', '- Dasar Pemrograman Block dengan PictoBlox untuk pembelajaran Informatika dan KKA\r\n- Integrasi PictoBlox dalam Pembelajaran dengan Model TPACK\r\n- Pelatihan Dasar Koding Aplikasi Interaktif Menggunakan PictoBlox untuk Guru Informatika dan KKA', '2025-11-25 17:30:00', 'SMP Bhakti Mulia', '/uploads/events/images/image-690ddfbea80906.64351534.png', 'https://s.id/MateriWorkshopNovember2025', 'https://s.id/TugasWorkshopNovember2025', 'https://s.id/Am0yX', NULL, 1, '2025-11-06 09:03:53', '2025-11-18 23:31:22', 0),
('481a2a9b-4629-489f-b6f0-38073f611855', 'Persiapan Sertifikasi GCE L1, L2, dan Gemini', '<p>Kegiatan ini dirancang khusus untuk guru-guru Informatika di Kabupaten Wonosobo guna meningkatkan kompetensi digital dengan standar global. Workshop ini akan mengupas tuntas materi ujian sertifikasi Google, strategi pengerjaan soal, hingga integrasi kecerdasan buatan (Gemini AI) dalam ekosistem Google Workspace for Education untuk mendukung efisiensi pembelajaran di kelas.</p>\n<p><strong>Materi Utama:</strong></p>\n<ul>\n<li>\n<p><strong>GCE Level 1:</strong> Penguasaan dasar alat Google (Classroom, Drive, Docs, Forms).</p>\n</li>\n<li>\n<p><strong>GCE Level 2:</strong> Strategi integrasi tingkat lanjut dan analisis data pembelajaran.</p>\n</li>\n<li>\n<p><strong>Gemini AI:</strong> Transformasi asisten mengajar digital untuk pembuatan konten edukatif dan otomatisasi administrasi guru.</p>\n</li>\n</ul>\n<p><strong>Rundown Kegiatan<br></strong>13.00 - 13.15 Pembukaan oleh Moderator dan Menyanyikan Indonesia Raya<br>13.15 - 13.30 Sambutan Ketua MGMP / perwakilannya<br>13.30 - 15.00 Materi Persiapan Sertifikasi GCE L1, L2, dan Gemini<br>15.00 - 15.25 Tanya Jawab<br>15.25 - 15.30 Penutupan</p>', '2026-02-25 06:00:00', 'Google Meet', '/uploads/events/images/6995727c1c05d.png', NULL, NULL, NULL, NULL, 0, '2026-02-17 04:21:59', '2026-02-28 04:53:17', 1),
('4e1684bb-b40d-4e8b-85b1-4ee632b33c3e', 'Pertemuan Rutin MGMP Informatika Februari 2026', 'Acara : Pertemuan Rutin MGMP Informatika Februari 2026\r\n- Penguatan CP, TP, ATP IF Semester 2 Kelas 7-9\r\n- Optimalisasi Web MGMP\r\n- Sosialisasi Permendikdasmen Nomor 1 Tahun 2026 dan Nomor 6 Tahun 2026', '2026-02-04 00:30:00', 'SMP Bhakti Mulia', '/uploads/events/event-6980601a29e008.36013739.png', NULL, NULL, NULL, NULL, 1, '2026-01-14 19:41:14', '2026-02-03 21:34:35', 0),
('6b7db257-0b1d-4c80-96de-dc50a76ef5c3', 'BBGTK - HGN 2025 : Peningkatan Kompetensi GTK - Kab. Wonosobo', 'Perancangan Pembelajaran dengan Memanfaatkan KKA', '2025-11-10 17:30:00', 'Hotel Dafam Wonosobo', '/uploads/events/images/image-690e160e4e1f98.69991727.png', 'https://s.bbgtkjateng.org/PKG-HGN-2025', 'https://s.bbgtkjateng.org/PKG-HGN-2025', 'https://s.bbgtkjateng.org/PKG-HGN-2025', NULL, 0, '2025-11-07 08:53:50', '2025-11-14 23:25:16', 0),
('92f86be7-7e0e-4c95-bf70-588e97c60120', 'Koding Asik dengan Python (Mulai dari 0)', '- Pemetaan CP Informatika dan KKA\r\n- Bedah Buku Pendamping Kelas 9 (Pemrograman Python)\r\n- Belajar Koding dengan Bahasa Pemrograman Python', '2025-11-18 17:30:00', 'SMP Bhakti Mulia', '/uploads/events/images/image-690e17d5741dc7.50313135.png', NULL, NULL, NULL, NULL, 1, '2025-11-07 09:01:25', '2025-11-10 19:10:05', 0),
('dbbb74b5-38d9-4ed7-b10e-6e85f19e09e9', 'Membuat Website Sekolah (Mulai dari 0)', '- Pelatihan Gratis\r\n- Membayar Akomodasi (Snack + Makan) dan hosting (free domain .sch.id) untuk 1 tahun', '2025-12-16 17:30:00', 'tbd', '/uploads/events/images/image-690f51da666ec4.79032489.png', '', '', '', NULL, 0, '2025-11-08 07:21:14', '2025-11-11 08:40:43', 0),
('e8bce916-b9db-474f-88cc-051350db7c1a', 'Persiapan Sertifikasi GCE L2, dan GCI (Google Certified Innovator)', '<p>Kegiatan ini dirancang khusus untuk guru-guru Informatika di Kabupaten Wonosobo guna meningkatkan kompetensi digital dengan standar global. Workshop ini akan mengupas tuntas materi ujian sertifikasi Google, strategi pengerjaan soal, hingga integrasi kecerdasan buatan (Gemini AI) dalam ekosistem Google Workspace for Education untuk mendukung efisiensi pembelajaran di kelas.</p>\n<p><strong>Materi Utama:</strong></p>\n<ul>\n<li>\n<p><strong>GCE Level 2:</strong> Strategi integrasi tingkat lanjut dan analisis data pembelajaran.</p>\n</li>\n<li>\n<p><strong>GCI:</strong> Program Inovator Besertifikasi Google for Education mengakui dan mendukung para pengajar unggulan yang bersemangat untuk tumbuh secara profesional, mengadvokasi teknologi yang memberikan dampak, dan berinovasi untuk meningkatkan kelas, sekolah dan komunitas lokal.</p>\n</li>\n</ul>\n<p><strong>Rundown Kegiatan</strong><br>10.00 - 10.10 Pembukaan oleh Moderator<br>10.10 - 10.20 Sambutan Ketua MGMP / perwakilannya<br>10.20 - 11.10 Materi Persiapan Sertifikasi GCE L1, L2, dan Gemini<br>11.10 - 11.25 Tanya Jawab<br>11.25 - 11.30 Penutupan</p>', '2026-03-04 12:00:00', 'Google Meet', '/uploads/events/images/69a4e09441bc1.png', NULL, NULL, NULL, NULL, 1, '2026-02-28 04:49:48', '2026-03-04 04:47:58', 1);
