('32f929e2-20d5-435a-a3c5-789346d5f005', 'Grid Garden', 'Grid Garden, dimana kamu menulis kode CSS untuk menumbuhkan kebun wortel anda! ', 'https://cssgridgarden.com/#id', NULL, 0, 1, '2026-03-02 02:00:06'),
('4340b281-ad01-447b-a78f-b7c6bfb1e8a0', 'Konversi Bilangan', 'Games seperti tetris dari Cisco ini bisa membantu Anda memahami konsep konversi bilangan.', 'https://learningcontent.cisco.com/games/binary/index.html', NULL, 0, 1, '2026-03-02 02:16:13'),
('5164d8b9-fb39-4554-987b-412772f5419b', 'CodeCombat', 'Belajar coding dan menggunakan AI, semua melalui kekuatan bermain', 'https://codecombat.com/', NULL, 0, 1, '2026-03-02 01:54:21'),
('a1d34e84-6a5b-4c2f-8a39-b066c1121279', 'Interland - Tangkas Berinternet', 'Games yang didesain oleh Google untuk memahami konsep Literasi Digital', 'https://beinternetawesome.withgoogle.com/id_id/interland', NULL, 0, 1, '2026-03-02 01:44:05'),
('a76668d7-8c3e-47b8-8403-c2194ebd44ed', 'Code Mongkey', 'Membantu seekor monyet mengambil pisang dengan menulis kode sederhana. Sangat cocok untuk mengasah logika dasar.', 'https://www.codemonkey.com/', NULL, 0, 1, '2026-03-02 01:56:53'),
('a9b708ae-6e91-4d7f-bd74-82804dc3af6e', 'Flexbox Froggy', 'Flexbox Froggy, tempat permainan dimana kamu membantu Froggy dan teman-teman dengan menulis kode CSS! ', 'https://flexboxfroggy.com/#id', NULL, 0, 1, '2026-03-02 01:59:13'),
('b799b444-c12a-46a9-8714-b8e752eaf247', 'Blockly', 'Mengasah kemampuan berpikir komputasional', 'https://blockly.games/', NULL, 0, 1, '2026-03-02 01:41:56'),
('eec78ef4-0d7b-4620-a6d1-af45cd58aa01', 'Code.org', 'Code.org® adalah organisasi nirlaba global terkemuka yang memastikan setiap siswa memiliki kesempatan untuk memahami bagaimana AI bekerja, bagaimana beralasan dengannya, dan bagaimana menciptakannya — bukan hanya menggunakannya.', 'https://code.org/id', NULL, 0, 1, '2026-03-02 02:03:45');
INSERT INTO `learning_cp` (`id`, `mapel`, `content`, `materi`, `updated_by`, `updated_at`) VALUES
('09d63cec-1b14-4384-a295-2e183055773c', 'KKA', '<p><strong>Berpikir Komputasional</strong></p>\n<p>Menerapkan berpikir komputasional untuk masalah sehari-hari maupun komputasi. Memahami konsep himpunan data terstruktur dan lembar kerja pengolah data. Menyelesaikan persoalan dengan data berstruktur sederhana. Menuliskan instruksi menggunakan kosakata terbatas atau simbol (pseudocode).</p>\n<p><strong>Literasi Digital </strong></p>\n<p>Menggunakan mesin pencari dan mengevaluasi kualitas informasi digital. Mengenal ekosistem media pers digital, membedakan fakta, opini, dan hoaks. Memanfaatkan aplikasi pengolah dokumen, lembar kerja, presentasi. Memahami komponen, fungsi, cara kerja komputer, serta konektivitas jaringan.</p>\n<p><strong>Algoritma &amp; Pemrograman </strong></p>\n<p>Menulis teks algoritmik terstruktur (logis, sistematis, bertahap). Membuat instruksi yang dapat dijalankan manusia maupun komputer. Menerapkan paradigma pemrograman prosedural dengan kompleksitas bertahap.</p>\n<p><strong>Analisis Data</strong></p>\n<p>Mengumpulkan, membersihkan, mengolah, dan menyajikan data sederhana. Menginterpretasi data untuk mendukung pengambilan keputusan dasar.&nbsp;</p>\n<p><strong>Kecerdasan Artifisial (AI) </strong></p>\n<p>Memahami konsep dasar AI, manfaat dan dampaknya. Mengevaluasi etika dan bias dalam penggunaan AI. Mencoba memanfaatkan AI sederhana untuk menyelesaikan masalah.</p>', '', '3b83adf6-bb10-11f0-85bd-00163e02c8b0', '2025-11-18 01:21:54'),
('1d920b8a-5974-4179-9a9e-8c0ab967d779', 'Informatika', '<p><strong>Berpikir Komputasional</strong></p>\n<p>Pada akhir fase D, peserta didik mampu memahami konsep himpunan data terstruktur dalam kehidupan sehari-hari, memahami konsep lembar kerja pengolah data dan menerapkan berpikir komputasional dalam menyelesaikan persoalan yang mengandung himpunan data berstruktur sederhana dengan volume kecil, dan mendisposisikan berpikir komputasional yang diperlukan pada berbagai bidang; mampu menuliskan sekumpulan instruksi dengan menggunakan sekumpulan kosakata terbatas atau simbol dalam format pseudocode.</p>\n<p><strong>Literasi Digital</strong></p>\n<p>Pada akhir fase D, peserta didik mampu memahami cara kerja dan penggunaan mesin pencari di internet, mengetahui kredibilitas sumber informasi digital dan mengenal ekosistem media pers digital, membedakan fakta dan opini, memahami pemanfaatan perkakas teknologi digital untuk membuat laporan, presentasi, serta analisis dan interpretasi data, mampu mendeskripsikan komponen, fungsi, dan cara kerja komputer, memahami konsep dan penerapan konektivitas jaringan lokal dan internet baik kabel maupun nirkabel, mengetahui jenis ruang publik virtual, memahami pemanfaatan media digital untuk produksi dan diseminasi konten; mampu memahami pentingnya menjaga rekam jejak digital, mengamalkan toleransi dan empati di dunia digital, memahami dampak perundungan digital, membuat kata sandi yang aman, memahami pengamanan perangkat dari berbagai jenis malware, memilah informasi yang bersifat privat dan publik, melindungi data pribadi dan identitas digital, memahami kesadaran penuh (mindfulness) di dunia digital.</p>', '', '405573c9-6c74-4c58-a9af-742d52dd6efa', '2026-01-04 20:39:43');
