('275d7efb-02e2-4f54-b630-10b472b64eae', 'undangan-pendamping', '036/MGMP-INFORMATIKA/XI/2025', '2025-11-26', 'Undangan KS Pendamping', 'Leonardo Hiendarto', 'dbbb74b5-38d9-4ed7-b10e-6e85f19e09e9', '3b83adf6-bb10-11f0-85bd-00163e02c8b0', '\n                    <div style=\"overflow: hidden; margin-bottom: 2rem;\"><div style=\"float: left;\"><p style=\"margin:0; line-height:1.5;\">Nomor : 036/MGMP-INFORMATIKA/XI/2025</p><p style=\"margin:0; line-height:1.5;\">Lamp : -</p><p style=\"margin:0; line-height:1.5;\">Hal&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;: Undangan</p></div><div style=\"float: right;\"><p style=\"margin:0; line-height:1.5;\">Wonosobo, 26 November 2025</p></div></div><div style=\"clear:both;\"></div>\n                    <p style=\"margin-bottom: 1rem; text-align: justify; line-height: 1.5;\">Kepada Yth.<br>Leonardo Hiendarto <br>SMP Bhakti Mulia Wonosobo<br>Di - Wonosobo</p>\n                    <p style=\"margin-bottom: 1rem; text-align: justify; line-height: 1.5;\">Dengan hormat,</p>\n                    <p style=\"margin-bottom: 1rem; text-align: justify; line-height: 1.5; text-indent: 40px;\">Sehubungan dengan pelaksanaan Membuat Website Sekolah (Mulai dari 0), maka dengan itu mohon dengan hormat kesediaan Bapak/Ibu untuk menghadiri acara tersebut yang akan dilaksanakan pada:</p>\n                    \n            <table style=\"width: 100%; border-collapse: collapse; margin: 1rem 0 1rem 40px;\">\n                <tbody>\n                    <tr><td style=\"width: 120px; vertical-align: top; padding: 2px 0;\">Hari/tanggal</td><td style=\"vertical-align: top; padding: 2px 0;\">: Rabu, 17 Desember 2025</td></tr>\n                    <tr><td style=\"vertical-align: top; padding: 2px 0;\">Waktu</td><td style=\"vertical-align: top; padding: 2px 0;\">: 07.30 WIB &ndash; selesai</td></tr>\n                    <tr><td style=\"vertical-align: top; padding: 2px 0;\">Tempat</td><td style=\"vertical-align: top; padding: 2px 0;\">: tbd</td></tr>\n                  