INSERT INTO `prompt_library` (`id`, `title`, `prompt_content`, `description`, `example_result`, `example_type`, `category`, `tags`, `is_premium`, `created_at`) VALUES
('342a276d-82b4-442f-bcc0-1d6fbf772823', 'Membuat Soal Informatika - Pilihan Ganda Kompleks', 'Saya adalah Guru Informatika kelas 7, tolong buatkan 10 soal pilihan ganda kompleks dengan tujuan pembelajaran membedakan fakta dan opini (kode LD-04). Pembuatan soal harus mengacu pada file yang sudah saya upload sebelumnya. Untuk setiap soal, buatkan stimulus yang relevan. Jawaban terdiri dari 5 pilihan (A, B, C, D, dan E). Kunci jawaban secara acak dari pilihan ganda yang ada dan jawaban benar ada 2. Karena ini 10 soal, maka porsi kunci jawaban untuk setiap pilhan jawaban harus sama. Pada pilhan jawaban, pastikan jumlah karakternya hampir sama, jangan sampai ada yang berbeda sehingga terlihat kalau itu jawaban. Buatkan dalam format excel yang saya kasih. Porsi soal terdiri dari 50% soal mudah, 30% soal menengah, dan 20% soal sukar. Jika soal membutuhkan gambar, boleh banget dikasih keterangan, biar nanti saya tambahkan gambar sesuai konteks secara manual.', 'Prompt ini saya gunakan untuk membuat soal Informatika Kelas 7', '', 'text', 'Teaching', '[]', 1, '2026-03-06 02:42:24'),
('6d0d2ed5-4429-4c30-8705-5f5760ba5fac', 'Membuat Soal Informatika - Pilihan Ganda', 'Saya adalah Guru Informatika kelas 7, tolong buatkan 10 soal pilihan ganda kompleks dengan tujuan pembelajaran memahami cara kerja dan penggunaan mesin pencari di internet (kode LD-01). Pembuatan soal harus mengacu pada file yang sudah saya upload sebelumnya. Untuk setiap soal, buatkan stimulus yang relevan. Jawaban terdiri dari 5 pilihan (A, B, C, D, dan E). Kunci jawaban secara acak dari pilihan ganda yang ada dan jawaban benar ada 2. Karena ini 10 soal, maka porsi kunci jawaban untuk setiap pilhan jawaban harus sama. Pada pilhan jawaban, pastikan jumlah karakternya hampir sama, jangan sampai ada yang berbeda sehingga terlihat kalau itu jawaban. Buatkan dalam format excel yang saya kasih. Porsi soal terdiri dari 50% soal mudah, 30% soal menengah, dan 20% soal sukar. Jika soal membutuhkan gambar, boleh banget dikasih keterangan, biar nanti saya tambahkan gambar sesuai konteks secara manual.', 'Prompt ini saya gunakan untuk membuat soal Informatika Kelas 7', '', 'text', 'Teaching', '[]', 1, '2026-03-06 01:19:44'),
('bda88d61-3aba-45ab-9f62-3ff1f5ad6bfb', 'Membuat Soal Informatika - Isian Singkat, Essay, dll', 'Saya adalah Guru Informatika kelas 7, tolong buatkan masing-masing 10 soal (BS (Benar Salah), MJ (Menjodohkan), IS (Isian Singkat), ES (Essay).) dengan tujuan pembelajaran membedakan fakta dan opini (kode LD-04). Jangan lupa berikan kunci jawaban, untuk essay boleh berikan hanya point pentingnya. Khusus untuk essay harus mengacu pada kemampuan keterampilan berpikir tingkat tinggi dan critical thingking skill, soal essay adalah soal terbuka dan merupakan soal yang ada korelasinya dengan kehidupan sehari-hari. Pembuatan soal harus mengacu pada file yang sudah saya upload sebelumnya. Untuk setiap soal, buatkan stimulus yang relevan. Buatkan dalam format excel yang saya kasih. Porsi soal terdiri dari 50% soal mudah, 30% soal menengah, dan 20% soal sukar. Jika soal membutuhkan gambar, boleh banget dikasih keterangan, biar nanti saya tambahkan gambar sesuai konteks secara manual.', 'Prompt ini saya gunakan untuk membuat soal Informatika Kelas 7', '', 'text', 'Teaching', '[]', 1, '2026-03-06 02:43:24');
INSERT INTO `questions` (`id`, `content`, `type`, `options`, `answer_key`, `explanation`, `level`, `mapel`, `kelas`, `tags`, `creator_id`, `status`, `created_at`, `updated_at`, `tp_code`) VALUES
('00146e1a-3898-4121-999f-3cfb120f4f3b', 'Seorang peneliti mengetikkan kueri pencarian: \"Energi Terbarukan\" AND Surya -Angin. Hasil seperti apa yang paling tepat sesuai dengan logika pencarian dari kueri tersebut?', 'single_choice', '[{\"id\":\"i1ioov\",\"text\":\"Memuat frasa acak energi terbarukan dengan energi tenaga angin.\",\"is_correct\":false},{\"id\":\"gogy4o\",\"text\":\"Memuat kata surya dan angin secara bersamaan di dalam situs web.\",\"is_correct\":false},{\"id\":\"3tb8b\",\"text\":\"Memuat frasa utuh energi terbarukan dan surya tapi tanpa angin.\",\"is_correct\":true},{\"id\":\"jilhnj\",\"text\":\"Memuat seluruh berita tentang energi kecuali surya dan juga angin.\",\"is_correct\":false}]', 'C', NULL, 'Sukar', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 09:02:19', '2026-03-06 09:02:19', 'LD-01'),
('002e898b-47b4-42e6-a430-a7e2fee66fd2', '<p>Budi diminta guru mencari informasi mengenai sejarah komputer. Budi perlu menggunakan mesin pencari (search engine) di perambannya. Manakah dari berikut ini yang merupakan contoh mesin pencari? (Pilih 2 jawaban benar)</p>', 'multiple_choice', '[{\"id\":\"dms0h\",\"text\":\"Mesin pencari web buatan Google yang sangat populer.\",\"is_correct\":true},{\"id\":\"aszp5d\",\"text\":\"Bing yang dikembangkan oleh perusahaan Microsoft.\",\"is_correct\":true},{\"id\":\"54motf\",\"text\":\"Microsoft Word untuk membuat dokumen teks baru.\",\"is_correct\":false},{\"id\":\"s3a1gq\",\"text\":\"Adobe Photoshop untuk mengedit gambar digitalnya.\",\"is_correct\":false},{\"id\":\"35coht\",\"text\":\"Sistem operasi Windows buatan Microsoft Corporation.\",\"is_correct\":false}]', 'A,B', NULL, 'Mudah', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 02:46:53', '2026-03-06 02:58:57', 'LD-01'),
('003dc5ad-93ef-49af-95f0-b0bd37bb24db', 'Mesin pencari menggunakan bot yang dikenal sebagai \'spider\' atau \'crawler\'. Apa tugas utama dari program bot perayap ini di internet? (Pilih 2 jawaban benar)', 'multiple_choice', '[{\"id\":\"few8u5\",\"text\":\"Menghapus situs web yang tidak berguna di internet ini.\",\"is_correct\":false},{\"id\":\"3g8zaa\",\"text\":\"Menyerang komputer pengguna agar terkena virusnya yaa.\",\"is_correct\":false},{\"id\":\"6w4x72\",\"text\":\"Mengubah tampilan desain dari seluruh situs internet ya.\",\"is_correct\":false},{\"id\":\"k71l3r\",\"text\":\"Mengunjungi halaman web untuk mengumpulkan data penting.\",\"is_correct\":true},{\"id\":\"x8mu1\",\"text\":\"Menjelajahi tautan web untuk proses pengindeksan sistem.\",\"is_correct\":true}]', 'D,E', NULL, 'Mudah', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 09:02:23', '2026-03-06 09:02:23', 'LD-01'),
('00703053-6016-45ba-8e56-e4c10388efc1', 'Tipe data logical (logika) memiliki dua nilai yaitu...', 'single_choice', '[{\"id\":\"91t1zd\",\"text\":\"angka dan teks\",\"is_correct\":false},{\"id\":\"pfj5gf\",\"text\":\"benar dan salah\",\"is_correct\":true},{\"id\":\"omf1nj\",\"text\":\"teks dan tanggal\",\"is_correct\":false},{\"id\":\"9bzhjj\",\"text\":\"angka dan huruf\",\"is_correct\":false}]', 'B', NULL, 'Mudah', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-02-11 14:22:40', '2026-02-11 14:22:40', 'LD-05'),
('00b0a40b-aebf-4b18-87bc-3922e38e6c11', 'Budi menggambar rute lokasi pesta nenek. Ia hanya menggambar jalan utama menuju rumah dan sengaja mengabaikan gambar pohon atau tiang listrik di sepanjang jalan.', 'single_choice', '[{\"id\":\"bwwzqo\",\"text\":\"Pemecahan masalah menjadi langkah yang kecil\",\"is_correct\":false},{\"id\":\"5wncmi\",\"text\":\"Pencarian kesamaan dari kasus permasalahan. \",\"is_correct\":false},{\"id\":\"nktzc\",\"text\":\"Proses abstraksi pada suatu masalah tersebut\",\"is_correct\":true},{\"id\":\"hocaht\",\"text\":\"Penulisan langkah langkah urutan yang logis \",\"is_correct\":false}]', 'C', NULL, 'Mudah', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-07 00:27:55', '2026-03-07 00:27:55', 'BK-01'),
('010ec1e1-f1f2-4496-95fd-8bdace6efcbb', 'Dalam praktik unplugged menggambar karakter monster, dua orang siswa mendapatkan hasil akhir gambar yang secara visual sangat jauh berbeda padahal instruksi algoritmanya sama. Analisislah akar permasalahan logikanya!', 'essay', '[]', 'Akar masalahnya terletak pada ambiguitas (ketidakjelasan) susunan Algoritma, di mana pembuat instruksi gagal memberikan detail ukuran, proporsi, atau letak koordinat yang spesifik. Selain itu, perbedaan kemampuan siswa dalam menginterpretasi kalimat abstrak (Abstraksi) juga menjadi pemicu utamanya.', NULL, 'Sedang', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-07 00:47:12', '2026-03-07 00:47:12', 'BK-01'),
('0110e827-5a08-4fc3-9318-4e2f4f98d6a3', 'Sebutkan perbedaan antara queue dan stack dalam struktur data!', 'essay', '[]', 'Queue menggunakan prinsip FIFO (antrean), sedangkan Stack menggunakan prinsip LIFO (tumpukan).', NULL, 'Sukar', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-02-11 14:34:57', '2026-02-11 14:34:57', 'BK-01'),
('01674a5a-9659-4c9b-8f0a-60a2dc27e283', 'Alamat sel B5 disebut sebagai...', 'single_choice', '[{\"id\":\"gyi8uv\",\"text\":\"sel relatif\",\"is_correct\":true},{\"id\":\"qliod\",\"text\":\"sel absolut\",\"is_correct\":false},{\"id\":\"qpsz5d\",\"text\":\"sel semi absolut\",\"is_correct\":false},{\"id\":\"wylpoo\",\"text\":\"sel ganda\",\"is_correct\":false}]', 'A', NULL, 'Mudah', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-02-11 14:22:41', '2026-02-11 14:22:41', 'BK-02'),
('02c2f04c-6981-4c74-af8b-aabce10b2d33', 'Panitia menyadari bahwa saat acara ulang tahun sebelumnya, selalu ada 10% tamu yang datang terlambat. Panitia lalu memundurkan jadwal potong kue sedikit lebih lambat pada tahun ini.', 'single_choice', '[{\"id\":\"i8z6nq\",\"text\":\"Dekomposisi jadwal secara terperinci \",\"is_correct\":false},{\"id\":\"dopig\",\"text\":\"Tahapan abstraksi bagi peserta telat \",\"is_correct\":false},{\"id\":\"jicp5\",\"text\":\"Pengenalan pola dari kegiatan berlalu\",\"is_correct\":true},{\"id\":\"7choyi\",\"text\":\"Pembuatan algoritma kehadiran peserta\",\"is_correct\":false}]', 'C', NULL, 'Sedang', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-07 00:28:01', '2026-03-07 00:28:01', 'BK-01'),
('02f1beea-0874-4495-8f90-dc544acac401', 'Jodohkanlah: Menyadari kecenderungan robot yang selalu menabrak objek berwarna gelap saat uji coba.', 'single_choice', '[{\"id\":\"9qqhe\",\"text\":\"Proses Isolasi Penyebab Abstraksi     \",\"is_correct\":false},{\"id\":\"kb8i8\",\"text\":\"Analisis Indikator Pengenalan Pola    \",\"is_correct\":true},{\"id\":\"5l44fc\",\"text\":\"Modifikasi Perintah Jalur Algoritma   \",\"is_correct\":false},{\"id\":\"hsih5l\",\"text\":\"Pembongkaran Sasis Secara Dekomposisi \",\"is_correct\":false},{\"id\":\"zqrcm\",\"text\":\"Perekaman Riwayat Kegagalan Tipe Stack\",\"is_correct\":false}]', 'B', NULL, 'Sukar', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-07 00:47:05', '2026-03-07 00:47:05', 'BK-01'),
('03b48372-7e5c-473f-9b3b-87456a3edb9c', 'Andi berargumen dengan temannya: \"Jaringan fiber optik mentransmisikan data menggunakan cahaya, sehingga ini adalah teknologi paling hebat saat ini.\" Analisis argumen Andi!', 'single_choice', '[{\"id\":\"b56f9\",\"text\":\"Keduanya adalah fakta karena kecepatan cahaya tidak dapat tertandingi.\\u200b\\u200b\\u200b\\u200b\",\"is_correct\":false},{\"id\":\"znczq6\",\"text\":\"Metode transmisi cahaya adalah opini, sebutan paling hebat adalah fakta.\\u200b\\u200b\",\"is_correct\":false},{\"id\":\"qmv7sm\",\"text\":\"Metode transmisi cahaya adalah fakta, sebutan paling hebat adalah opini.\\u200b\\u200b\",\"is_correct\":true},{\"id\":\"l4gcjl\",\"text\":\"Keduanya adalah opini karena teknologi akan terus berkembang sangat pesat.\",\"is_correct\":false}]', 'C', NULL, 'Sedang', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 01:15:47', '2026-03-06 01:15:47', 'LD-04'),
('03d9fb10-7bc9-4ed6-8a51-c168fa1ff686', '[Gambar: Berbagai logo aplikasi komputer] Dari berbagai logo yang ada, manakah yang merupakan contoh layanan mesin pencari (search engine) di internet?', 'single_choice', '[{\"id\":\"ih4gl\",\"text\":\"Microsoft Word dan program Adobe Photoshop.\",\"is_correct\":false},{\"id\":\"b4a67b\",\"text\":\"Mesin Google Search dan juga Microsoft Bing.\",\"is_correct\":true},{\"id\":\"40sos\",\"text\":\"Sistem Operasi Windows dan juga Linux Ubuntu.\",\"is_correct\":false},{\"id\":\"au5z6f\",\"text\":\"Peramban Mozilla Firefox dan Google Chromes.\",\"is_correct\":false}]', 'B', NULL, 'Mudah', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 09:02:20', '2026-03-06 09:02:20', 'LD-01'),
('04526b4e-0e2c-42b0-a151-f50de37401de', 'Identifikasi kerangka regulasi struktural media berikut. Pernyataan: Konsep kebijakan yang mendikte platform teknologi multinasional agar memberikan kompensasi finansial yang berkeadilan kepada perusahaan media pers sebagai produsen konten.', 'single_choice', '[{\"id\":\"ki9wjd\",\"text\":\"Algoritma Pemeringkatan (Ranking)\",\"is_correct\":false},{\"id\":\"zka7v\",\"text\":\"Publisher Rights (Hak Penerbit)\",\"is_correct\":true},{\"id\":\"suty4\",\"text\":\"Sistem Pembayaran Paywall\",\"is_correct\":false},{\"id\":\"ctb1mc\",\"text\":\"Hukum Perlindungan Data Pribadi\",\"is_correct\":false},{\"id\":\"cs0f6s\",\"text\":\"Standar Hak Kekayaan Intelektual\",\"is_correct\":false}]', 'B', NULL, 'Sukar', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 09:25:27', '2026-03-06 09:25:27', 'LD-03'),
