('494674cb-07a7-4001-a4ec-52fbe2ecf22a', 'Beredar pesan berantai di grup WhatsApp keluarga tentang kesehatan. Bagaimana cara terbaik memastikan itu fakta?', 'single_choice', '[{\"id\":\"1vsxna\",\"text\":\"Mencari referensi dari sumber medis tepercaya.\",\"is_correct\":true},{\"id\":\"9i3it\",\"text\":\"Membagikan langsung ke seluruh teman dekat.\",\"is_correct\":false},{\"id\":\"j172fj\",\"text\":\"Mempercayai pesan karena dari anggota keluarga.\",\"is_correct\":false},{\"id\":\"68uh5l\",\"text\":\"Mengabaikan pesan tanpa membaca isinya sama.\",\"is_correct\":false}]', 'A', NULL, 'Mudah', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 01:27:52', '2026-03-06 01:27:52', 'LD-04'),
