('618986b0-5ff3-47f2-b870-e6e1ce977409', 'Dalam sebuah forum diskusi online, Rio menulis: \"Sistem operasi Linux bersifat open source. Penggunaannya juga terasa lebih nyaman daripada Windows.\" Bagaimana status kedua kalimat itu?', 'single_choice', '[{\"id\":\"7ox4u5i\",\"text\":\"Bagian open source adalah fakta, kenyamanan penggunaan adalah opini.\",\"is_correct\":true},{\"id\":\"63ydit\",\"text\":\"Bagian open source adalah opini, kenyamanan penggunaan adalah fakta.\",\"is_correct\":false},{\"id\":\"9e0fva\",\"text\":\"Keduanya merupakan fakta karena Linux terbukti gratis untuk publik.\\u200b\",\"is_correct\":false},{\"id\":\"o8j184\",\"text\":\"Keduanya merupakan opini karena sangat bergantung pada penggunanya.\\u200b\",\"is_correct\":false}]', 'A', NULL, 'Sedang', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 01:15:47', '2026-03-06 01:15:47', 'LD-04'),
