('63ca29be-f797-4c34-bfd3-d562792e0783', '[Gambar: Perbandingan Hard Disk dan SSD] Banyak komputer modern saat ini beralih menggunakan Solid State Drive (SSD) untuk menggantikan Hard Disk Drive (HDD). Apakah perbedaan cara kerja utama di antara keduanya? (Pilih 2 jawaban benar)', 'multiple_choice', '[{\"id\":\"g1yk1k\",\"text\":\"HDD tidak butuh aliran daya listrik sama sekali lho. \",\"is_correct\":false},{\"id\":\"h088e\",\"text\":\"SSD menggunakan piringan magnetik yang berputar ya.  \",\"is_correct\":false},{\"id\":\"hx5a\",\"text\":\"SSD bekerja lebih cepat karena memakai memori flash. \",\"is_correct\":true},{\"id\":\"tvbq4c\",\"text\":\"HDD jauh lebih tahan dari guncangan dibandingkan SSD.\",\"is_correct\":false},{\"id\":\"is5or\",\"text\":\"HDD memakai komponen mekanis sehingga lebih lambat.  \",\"is_correct\":true}]', 'C,E', NULL, 'Sukar', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 09:31:28', '2026-03-06 09:31:28', 'LD-06'),
