('6be35fd5-83d9-42ae-b61e-9bc9d1bc9fb4', 'Meskipun mesin pencari memiliki indeks miliaran halaman, ada bagian internet yang tidak dapat dilacak (diindeks) oleh mesin pencari standar. Bagian ini dikenal dengan istilah...', 'single_choice', '[{\"id\":\"u3bth8\",\"text\":\"Surface Web yang sangat mudah diakses oleh semua orang.\",\"is_correct\":false},{\"id\":\"ucy4c\",\"text\":\"Deep Web yang memerlukan otentikasi atau akses spesifik.\",\"is_correct\":true},{\"id\":\"14i5y\",\"text\":\"World Wide Web yang menjadi basis dari seluruh jaringan.\",\"is_correct\":false},{\"id\":\"w8x0d\",\"text\":\"Local Area Network yang ada di dalam sebuah gedung kaca.\",\"is_correct\":false}]', 'B', NULL, 'Sukar', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 02:46:49', '2026-03-06 02:46:49', 'LD-01'),
