('88dd965e-de4e-4719-979f-10252da5c91f', 'Dalam proyek pesta ulang tahun nenek, Budi membagi peran kepada seluruh keluarga: Ayah mengurus transportasi, Ibu memasak, dan Adik mendekorasi.', 'single_choice', '[{\"id\":\"7kadwl\",\"text\":\"Abstraksi pada suatu masalah.\",\"is_correct\":false},{\"id\":\"pbo95m\",\"text\":\"Pengenalan pola tugas harian.\",\"is_correct\":false},{\"id\":\"s5k6kg\",\"text\":\"Dekomposisi persoalan proyek.\",\"is_correct\":true},{\"id\":\"h5nk48\",\"text\":\"Algoritma penyelesaian tugas.\",\"is_correct\":false}]', 'C', NULL, 'Mudah', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-07 00:27:56', '2026-03-07 00:27:56', 'BK-01'),
