('89fe5952-23e9-48d4-a4b6-3477abbf9b17', 'Ibu pergi ke pasar untuk keperluan pesta. Ia mencatat di kertas: 1. Beras, 2. Telur, 3. Gula, 4. Sayur. Catatan Ibu ini adalah contoh dari himpunan data struktur...', 'single_choice', '[{\"id\":\"67d13\",\"text\":\"Himpunan data struktur Graph.\",\"is_correct\":false},{\"id\":\"hwyiq\",\"text\":\"Himpunan data struktur List. \",\"is_correct\":true},{\"id\":\"wx9ahm\",\"text\":\"Himpunan data struktur Tree. \",\"is_correct\":false},{\"id\":\"f00z73\",\"text\":\"Himpunan data struktur Queue.\",\"is_correct\":false}]', 'B', NULL, 'Mudah', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-07 00:28:03', '2026-03-07 00:28:03', 'BK-01'),
