('b29d4b39-8376-4a02-9f71-450c2c28a84d', 'Saat mesin pencari menampilkan daftar hasil, terdapat potongan teks kecil di bawah judul tautan yang memberikan gambaran isi halaman. Potongan teks tersebut dinamakan...', 'single_choice', '[{\"id\":\"7cjcqo\",\"text\":\"URL (Uniform Resource Locator) alamat website resminya.\",\"is_correct\":false},{\"id\":\"0ftny\",\"text\":\"Bot (Program Otomatis) perayap dari mesin pencari itu.\",\"is_correct\":false},{\"id\":\"xf8pt9\",\"text\":\"Cache (Penyimpanan Sementara) pada peramban komputernya.\",\"is_correct\":false},{\"id\":\"9dvczh\",\"text\":\"Snippet (Cuplikan Teks) ringkasan konten halaman webnya.\",\"is_correct\":true}]', 'D', NULL, 'Sedang', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 09:02:20', '2026-03-06 09:02:20', 'LD-01'),
