('b71fa4ff-68e9-43ad-965f-e59ca772d9d1', 'Pada aktivitas \'Menyusun Algoritma Monster\', siswa diminta menggambar monster persis sesuai dengan instruksi yang diberikan oleh guru selangkah demi selangkah.', 'single_choice', '[{\"id\":\"y8wq4s\",\"text\":\"Memahami esensi urutan langkah algoritmik. \",\"is_correct\":true},{\"id\":\"qne1nv\",\"text\":\"Melatih kemampuan melukis agar lebih indah.\",\"is_correct\":false},{\"id\":\"un2ap\",\"text\":\"Mengabaikan setiap instruksi yang tersulit.\",\"is_correct\":false},{\"id\":\"6n2qz8\",\"text\":\"Memecah monster menjadi fragmen yang kecil.\",\"is_correct\":false}]', 'A', NULL, 'Mudah', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-07 00:27:57', '2026-03-07 00:27:57', 'BK-01'),
('b769d161-c4be-4f21-9165-4e1053e8600b', 'Data instruksi bawaan pabrik yang tersimpan di dalam modul Read Only Memory (ROM) bersifat volatile, yang bermakna instruksi tersebut akan menguap atau terhapus total ketika daya listrik komputer diputus.', 'true_false', '[{\"id\":\"kk72w\",\"text\":\"Benar\",\"is_correct\":false},{\"id\":\"fdfevp\",\"text\":\"Salah\",\"is_correct\":true}]', 'Salah', NULL, 'Sukar', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 09:37:50', '2026-03-06 09:37:50', 'LD-06'),
