('f3d3945f-ba48-4b33-a475-fb024c374cdf', 'Budi membaca berita melalui situs web kompas.com menggunakan telepon pintarnya. Situs web tersebut dikategorikan sebagai bagian dari ekosistem media pers digital karena...', 'single_choice', '[{\"id\":\"qh596b\",\"text\":\"Menyajikan informasi berita oleh tim redaksi resmi.\",\"is_correct\":true},{\"id\":\"w7ww1l\",\"text\":\"Menampilkan video hiburan kiriman dari warganet ya.\",\"is_correct\":false},{\"id\":\"onu5p9\",\"text\":\"Menjual barang kebutuhan sehari-hari secara daring.\",\"is_correct\":false},{\"id\":\"4ungc\",\"text\":\"Menyediakan layanan berkirim pesan secara personal.\",\"is_correct\":false}]', 'A', NULL, 'Mudah', 'Informatika', '7', NULL, '2a4a92a0-ad38-4c99-b55d-41e6e0b2a1f6', 'verified', '2026-03-06 09:21:23', '2026-03-06 09:21:23', 'LD-03'),
